// Đổi link ngắn ?p=<path trong bucket> thành link XEM TRỰC TIẾP:
// - excel/word/powerpoint -> Office Viewer (xem ngay trên điện thoại, không phải tải về;
//   giới hạn của Office Viewer: file ~10MB trở xuống)
// - pdf / video / ảnh     -> mở thẳng URL Storage, trình duyệt tự render
// Path phải nằm trong bucket task-attachments (chặn '..' để không trỏ đi nơi khác).
const q = $input.first().json.query || {};
const p = String(q.p || '');
const BUCKET_BASE = 'https://ngwkzicrnspeggunsblr.supabase.co/storage/v1/object/public/task-attachments/';
const FALLBACK = 'https://amazing-frangollo-eb56a9.netlify.app';

let target = FALLBACK;
if (p && !p.includes('..')) {
    const raw = BUCKET_BASE + p;
    const m = p.toLowerCase().match(/\.([a-z0-9]+)$/);
    const ext = m ? m[1] : '';
    target = ['xlsx', 'xls', 'docx', 'doc', 'pptx', 'ppt'].includes(ext)
        ? 'https://view.officeapps.live.com/op/view.aspx?src=' + encodeURIComponent(raw)
        : raw;
}
return [{ json: { target } }];

// ==============================================================
// TẠO NỘI DUNG ẢNH (định kỳ / theo yêu cầu)
// - Item 1        : Bảng tổng hợp công việc cả phòng
// - Item 2..n     : Bảng riêng của TỪNG NGƯỜI đang có việc
// Mỗi item đầu ra : { html, message_text } -> đi vào CHUỖI GỬI CHUNG
// Không hardcode tên nhân viên - lấy trực tiếp từ bảng nhan_vien
// VIỆC NHÓM 2026-07-17: đọc cột assignee_ids (text[]) — 1 việc giao nhiều người.
// - Bảng tổng hợp: ô "Người làm" liệt kê ĐỦ mọi thành viên (mỗi người 1 dòng avatar+tên).
// - Bảng cá nhân : việc nhóm xuất hiện trong bảng của TỪNG thành viên.
// - Fallback     : dòng chưa migrate dùng assignee_id; cũ hơn nữa dùng cột name.
// ==============================================================
const tasks = $('Lấy công việc').all().map(i => i.json).filter(t => t && t.id);
const nhanVien = $('Lấy nhân viên').all().map(i => i.json).filter(n => n && n.name);

const GROUP_ID = 'deb64378401ba945f00a';
const avatarMap = {};
const nvById = {};
const nvByName = {};
nhanVien.forEach(nv => {
    avatarMap[nv.name] = nv.avatar || '';
    nvById[nv.id] = nv;
    nvByName[nv.name] = nv;
});

// Danh sách thành viên của 1 việc (bản n8n của memberIds() trong src/lib/taskAssignees.js)
function memberIdsOf(t) {
    const raw = Array.isArray(t.assignee_ids) && t.assignee_ids.length
        ? t.assignee_ids
        : (t.assignee_id ? [t.assignee_id] : []);
    const seen = new Set(); const out = [];
    for (const id of raw) { if (id && !seen.has(id)) { seen.add(id); out.push(id); } }
    return out;
}
function memberNamesOf(t) {
    const names = memberIdsOf(t).map(id => (nvById[id] || {}).name).filter(Boolean);
    return names.length ? names : (t.name ? [t.name] : []);
}

// ===== AVATAR (ảnh đại diện nhân viên) =====
// DB lưu đường dẫn tương đối '/avatars/x.webp'. HCTI render trên server riêng nên
// PHẢI ghép thành URL tuyệt đối theo tên miền app đã deploy. Đổi APP_BASE bên dưới.
const APP_BASE = 'https://amazing-frangollo-eb56a9.netlify.app'; // vd: 'https://qlsx-tgln.netlify.app' (KHÔNG có dấu / ở cuối)
function avatarUrl(p) {
    if (!p) return '';
    if (/^https?:\/\//i.test(p)) return p;            // đã là URL tuyệt đối
    return APP_BASE.replace(/\/+$/, '') + (p.charAt(0) === '/' ? p : '/' + p);
}
function initials(name) {
    return (name || '?').trim().split(/\s+/).map(w => w[0]).slice(-2).join('').toUpperCase() || '?';
}
// Avatar lớn cho tiêu đề bảng cá nhân; nếu không có ảnh -> chữ cái đầu tên
function avatarBig(name) {
    const u = avatarUrl(avatarMap[name]);
    return u ? `<img class="hdr-av" src="${u}" alt=""/>`
             : `<div class="hdr-av hdr-av-fb">${initials(name)}</div>`;
}
// Avatar nhỏ trong ô "Người làm" của bảng tổng hợp
function avatarSmall(name) {
    const u = avatarUrl(avatarMap[name]);
    return u ? `<img class="cell-av" src="${u}" alt=""/>`
             : `<div class="cell-av cell-av-fb">${initials(name)}</div>`;
}

// ===== MÚI GIỜ (fix lệch -7 tiếng) =====
// Server n8n chạy UTC nên new Date().getHours() trả giờ UTC (10:00 VN in ra 03:00).
// Mọi format/đếm ngày phải ÉP Asia/Ho_Chi_Minh, KHÔNG dùng getHours()/setHours().
const VN_TZ = 'Asia/Ho_Chi_Minh';

function formatDateTime(isoString) {
    try {
        const parts = new Intl.DateTimeFormat('en-GB', {
            timeZone: VN_TZ, hour12: false,
            day: '2-digit', month: '2-digit', year: 'numeric',
            hour: '2-digit', minute: '2-digit'
        }).formatToParts(new Date(isoString));
        const g = t => parts.find(x => x.type === t).value;
        return `${g('day')}/${g('month')}/${g('year')} ${g('hour')}:${g('minute')}`;
    } catch (e) { return isoString; }
}

// Số thứ tự NGÀY theo giờ VN (ngày kể từ epoch) — đếm "còn/trễ X ngày" đúng cả quanh nửa đêm VN.
function vnDayNumber(dateLike) {
    const s = new Intl.DateTimeFormat('en-CA', { timeZone: VN_TZ, year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date(dateLike));
    return Math.round(Date.parse(s + 'T00:00:00Z') / 86400000);
}
const todayVn = vnDayNumber(Date.now());

function statusInfo(dueDate) {
    if (!dueDate) return { text: '', cls: '', warn: '', color: '' };
    const diff = vnDayNumber(dueDate) - todayVn;
    if (diff < 0)   return { text: 'QUÁ HẠN',  cls: 'badge-danger',  warn: `Trễ ${Math.abs(diff)} ngày`, color: '#ef4444' };
    if (diff === 0) return { text: 'HÔM NAY',  cls: 'badge-warning', warn: 'Đến hạn',                    color: '#f59e0b' };
    return { text: 'ĐANG LÀM', cls: 'badge-success', warn: `Còn ${diff} ngày`, color: '#10b981' };
}

const CSS = `
        body, html { margin: 0; padding: 0; width: 1920px; min-height: 1080px; background-color: #f1f5f9; font-family: 'Segoe UI', Arial, sans-serif; }
        .header-title { width: 100%; background: #1e293b; color: white; font-size: 55px; padding: 30px 0; font-weight: bold; text-transform: uppercase; display: flex; align-items: center; justify-content: center; gap: 44px; }
        .hdr-av { width: 150px; height: 150px; border-radius: 50%; object-fit: cover; flex-shrink: 0; border: 8px solid rgba(255,255,255,0.92); box-shadow: 0 8px 22px rgba(0,0,0,0.45); }
        .hdr-av-fb { display: flex; align-items: center; justify-content: center; background: linear-gradient(135deg,#6366f1,#8b5cf6); color: #fff; font-size: 76px; }
        table { width: 100%; border-collapse: collapse; table-layout: fixed; background: white; }
        th { background: #4f46e5; color: white; font-size: 38px; padding: 25px 10px; border-bottom: 6px solid #3730a3; }
        td { padding: 30px 15px; font-size: 38px; vertical-align: middle; border-bottom: 2px solid #e2e8f0; word-wrap: break-word; line-height: 1.3; }
        tr:nth-child(even) { background-color: #f8fafc; }
        th:nth-child(1) { width: 10%; } th:nth-child(2) { width: 33%; } th:nth-child(3) { width: 17%; }
        th:nth-child(4) { width: 15%; } th:nth-child(5) { width: 13%; } th:nth-child(6) { width: 12%; }
        .text-center { text-align: center; } .font-bold { font-weight: bold; } .text-primary { color: #1e3a8a; }
        .text-id { color: #64748b; font-size: 30px; text-align: center; }
        .cell-person { display: flex; align-items: center; justify-content: center; gap: 18px; }
        .cell-person-multi { display: flex; flex-direction: column; align-items: center; gap: 14px; }
        .cell-av { width: 80px; height: 80px; border-radius: 50%; object-fit: cover; flex-shrink: 0; box-shadow: inset 0 0 0 2px rgba(0,0,0,0.12); }
        .cell-av-fb { display: inline-flex; align-items: center; justify-content: center; background: #6366f1; color: #fff; font-size: 34px; font-weight: 700; }
        .badge { padding: 12px 20px; border-radius: 10px; color: white; font-weight: bold; display: inline-block; font-size: 28px; }
        .badge-danger { background: #ef4444; } .badge-warning { background: #f59e0b; } .badge-success { background: #10b981; }
`;

// Bảng nhiều việc → chỉ hiện số 📎, không nhúng ảnh từng việc (bảng sẽ dài vô hạn)
const attBadge = t => (Array.isArray(t.attachments) && t.attachments.length)
    ? ` <span style="color:#4f46e5;font-weight:800;">📎${t.attachments.length}</span>` : '';

function buildTable(title, list, headerName) {
    const sorted = [...list].sort((a, b) => {
        // Sắp theo tên thành viên ĐẦU TIÊN (người đại diện) rồi tới hạn chót
        const nameA = (memberNamesOf(a)[0] || 'Chưa giao').toLowerCase();
        const nameB = (memberNamesOf(b)[0] || 'Chưa giao').toLowerCase();
        if (nameA < nameB) return -1;
        if (nameA > nameB) return 1;
        const dateA = a.due_date ? new Date(a.due_date).getTime() : 0;
        const dateB = b.due_date ? new Date(b.due_date).getTime() : 0;
        return dateA - dateB;
    });

    let rows = '';
    sorted.forEach(t => {
        const s = statusInfo(t.due_date);
        // VIỆC NHÓM: liệt kê ĐỦ thành viên, mỗi người một dòng avatar + tên
        const names = memberNamesOf(t);
        const personCell = names.length
            ? `<div class="cell-person-multi">${names.map(n => `<div class="cell-person">${avatarSmall(n)}<span>${n}</span></div>`).join('')}</div>`
            : `<div class="cell-person"><span>Chưa giao</span></div>`;
        rows += `
        <tr>
            <td class="text-id">${t.id || ''}</td>
            <td class="font-bold text-primary">${t.title}${attBadge(t)}</td>
            <td class="text-center font-bold" style="background-color: #fefce8;">${personCell}</td>
            <td class="text-center" style="font-size: 32px;">${t.due_date ? formatDateTime(t.due_date) : 'N/A'}</td>
            <td class="text-center"><span class="badge ${s.cls}">${s.text}</span></td>
            <td class="text-center font-bold" style="color: ${s.color};">${s.warn}</td>
        </tr>`;
    });

    // Tiêu đề: bảng cá nhân có avatar lớn bên trái; bảng tổng hợp chỉ có chữ
    const header = headerName
        ? `<div class="header-title">${avatarBig(headerName)}<span>${title}</span></div>`
        : `<div class="header-title"><span>${title}</span></div>`;

    return `<!DOCTYPE html>
<html lang="vi">
<head><meta charset="UTF-8"><style>${CSS}</style></head>
<body>
    ${header}
    <table>
        <thead><tr><th>Mã CV</th><th>Tên công việc</th><th>Người làm</th><th>Hạn hoàn thành</th><th>Trạng thái</th><th>Cảnh báo</th></tr></thead>
        <tbody>${rows}</tbody>
    </table>
</body>
</html>`;
}

const out = [];

// 1) Bảng tổng hợp cả phòng (không avatar lớn ở tiêu đề, nhưng mỗi dòng có avatar nhỏ)
if (tasks.length > 0) {
    out.push({ json: {
        html: buildTable('BẢNG TỔNG HỢP CÔNG VIỆC PHÒNG', tasks, null),
        message_text: `Tổng hợp công việc [@${GROUP_ID}]`
    }});
}

// 2) Bảng riêng từng người CÓ việc — VIỆC NHÓM tính cho MỌI thành viên
//    (nên bảng cá nhân của cả 3 người trong nhóm đều chứa việc đó).
const byId = {};
tasks.forEach(t => {
    let ids = memberIdsOf(t);
    // Fallback dòng rất cũ chỉ có cột name: tra ngược ra id để vẫn có bảng cá nhân
    if (!ids.length && t.name && nvByName[t.name]) ids = [nvByName[t.name].id];
    ids.forEach(id => { if (nvById[id]) (byId[id] = byId[id] || []).push(t); });
});

Object.keys(byId)
    .sort((a, b) => (nvById[a].name || '').localeCompare(nvById[b].name || '', 'vi'))
    .forEach(id => {
        const nv = nvById[id];
        const oaId = nv.id_zalo_oa;
        if (!oaId) return; // không tìm thấy id_zalo_oa -> bỏ qua ảnh cá nhân, vẫn có trong bảng tổng hợp
        out.push({ json: {
            html: buildTable(`CÔNG VIỆC CỦA ${nv.name.toUpperCase()}`, byId[id], nv.name),
            message_text: `[@${oaId}] Làm ăn quá phọt phẹt!`
        }});
    });

return out;

// ==============================================================
// TẠO THẺ CHI TIẾT khi 1 công việc được cập nhật (Webhook cập nhật task)
// Đầu vào : Lấy công việc (cập nhật) + Lấy tiến độ + Lấy nhân viên (cập nhật)
// Đầu ra  : 1 item { html, message_text } -> đi vào CHUỖI GỬI CHUNG
// VIỆC NHÓM 2026-07-17: app gửi body.assignees = [{id, name, email}, ...] (đủ cả nhóm).
// Tag [@id_zalo_oa] cho MỌI thành viên. body.assignee cũ vẫn còn (name = chuỗi gộp
// "Ngọc, Phong") để tương thích ngược — payload cũ 1 người vẫn chạy nguyên.
// ==============================================================
const task = $('Lấy công việc (cập nhật)').first().json || {};
const webhookBody = $('Webhook cập nhật task').first().json.body || {};

// Node 'Lấy nhân viên (cập nhật)' giờ là Get Many (toàn bộ ~16 dòng) -> tra theo ID.
// KHÔNG tra theo tên nữa: tên việc nhóm là chuỗi gộp "Ngọc, Phong" nên lọc name không khớp ai.
let allNv = [];
try { allNv = $('Lấy nhân viên (cập nhật)').all().map(i => i.json).filter(n => n && n.id); } catch (e) { allNv = []; }
const nvById = {};
allNv.forEach(n => { nvById[n.id] = n; });

const members = Array.isArray(webhookBody.assignees) && webhookBody.assignees.length
    ? webhookBody.assignees
    : (webhookBody.assignee && webhookBody.assignee.id ? [webhookBody.assignee] : []);

const nvList = members.map(m => nvById[m.id]).filter(Boolean);
const nv = nvList[0] || {};   // avatar trên thẻ = người đầu tiên trong nhóm

// Các dòng tiến độ của task (đã lọc theo task_id ở node trước)
const tienDo = $input.all().map(i => i.json).filter(r => r && r.task_id);

// ===== AVATAR (ảnh đại diện nhân viên) =====
// DB lưu đường dẫn tương đối '/avatars/x.webp'. HCTI render trên server riêng nên
// PHẢI ghép thành URL tuyệt đối theo tên miền app đã deploy. Đổi APP_BASE bên dưới.
const APP_BASE = 'https://amazing-frangollo-eb56a9.netlify.app'; // vd: 'https://qlsx-tgln.netlify.app' (KHÔNG có dấu / ở cuối)
function avatarUrl(p) {
    if (!p) return '';
    if (/^https?:\/\//i.test(p)) return p;
    return APP_BASE.replace(/\/+$/, '') + (p.charAt(0) === '/' ? p : '/' + p);
}

// ===== MÚI GIỜ (fix lệch -7 tiếng) =====
// Server n8n chạy UTC nên new Date().getHours() trả giờ UTC (10:00 VN in ra 03:00).
// Mọi format/đếm ngày phải ÉP Asia/Ho_Chi_Minh, KHÔNG dùng getHours()/setHours().
const VN_TZ = 'Asia/Ho_Chi_Minh';

function formatDateTime(isoString) {
    try {
        const parts = new Intl.DateTimeFormat('en-GB', {
            timeZone: VN_TZ, hour12: false,
            day: '2-digit', month: '2-digit', year: 'numeric',
            hour: '2-digit', minute: '2-digit'
        }).formatToParts(new Date(isoString));
        const g = t => parts.find(x => x.type === t).value;
        return `${g('day')}/${g('month')}/${g('year')} ${g('hour')}:${g('minute')}`;
    } catch (e) { return isoString; }
}

// Số thứ tự NGÀY theo giờ VN (ngày kể từ epoch) — đếm "còn/trễ X ngày" đúng cả quanh nửa đêm VN.
function vnDayNumber(dateLike) {
    const s = new Intl.DateTimeFormat('en-CA', { timeZone: VN_TZ, year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date(dateLike));
    return Math.round(Date.parse(s + 'T00:00:00Z') / 86400000);
}
const todayVn = vnDayNumber(Date.now());

// ===== BỘ ICON SVG (nét trắng, dùng chung cho nhãn) =====
const ICONS = {
    content: `<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><rect x="8" y="2" width="8" height="4" rx="1"/><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><path d="M9 13h6M9 17h4"/></svg>`,
    clock:   `<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="9"/><path d="M12 7v5l3 2"/></svg>`,
    trend:   `<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 17 9 11 13 15 21 7"/><polyline points="15 7 21 7 21 13"/></svg>`,
    user:    `<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="8" r="4"/><path d="M4 21v-1a6 6 0 0 1 6-6h4a6 6 0 0 1 6 6v1"/></svg>`,
    alert:   `<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3 2 20h20L12 3z"/><path d="M12 10v4"/><path d="M12 17.5h.01"/></svg>`,
    check:   `<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="9"/><path d="M8 12l3 3 5-6"/></svg>`
};
const badgeIcon = (name) => `<span class="badge-ic">${ICONS[name]}</span>`;

// VIỆC NHÓM: tên hiển thị = đủ mọi thành viên. Fallback về dữ liệu cũ khi payload không có assignees.
const assigneeName = members.length
    ? members.map(m => m.name).join(', ')
    : (task.name || (webhookBody.assignee && webhookBody.assignee.name) || 'Chưa giao');
const formattedDueDate = task.due_date ? formatDateTime(task.due_date) : 'N/A';

// Avatar đưa vào ô BÊN TRÁI của dòng đầu. Không có ảnh -> vòng tròn chữ cái đầu tên
// (lấy tên người đầu tiên, không lấy chuỗi gộp).
const avUrl = avatarUrl(nv.avatar);
const heroInitials = (nv.name || assigneeName || '?').trim().split(/\s+/).map(w => w[0]).slice(-2).join('').toUpperCase() || '?';
const rowAvatar = avUrl
    ? `<img class="av" src="${avUrl}" alt=""/>`
    : `<div class="av av-fb">${heroInitials}</div>`;

// Tình trạng + kiểu cảnh báo cho cả thẻ
let statusHtml = `<span class="badge badge-secondary">${badgeIcon('clock')} Chưa có hạn</span>`;
let cardClass = '';
let statusIcon = ICONS.check;
let statusRowColor = 'row-status-neutral';
if (task.due_date) {
    const diffDays = vnDayNumber(task.due_date) - todayVn;
    if (diffDays < 0) {
        statusHtml = `<span class="badge badge-danger">${badgeIcon('alert')} Quá hạn ${Math.abs(diffDays)} ngày</span>`;
        cardClass = 'card-overdue'; statusIcon = ICONS.alert; statusRowColor = 'row-status-danger';
    } else if (diffDays === 0) {
        statusHtml = `<span class="badge badge-warning">${badgeIcon('alert')} Hạn hôm nay</span>`;
        cardClass = 'card-today'; statusIcon = ICONS.alert; statusRowColor = 'row-status-warning';
    } else if (diffDays <= 2) {
        statusHtml = `<span class="badge badge-warning">${badgeIcon('clock')} Còn ${diffDays} ngày</span>`;
        cardClass = 'card-today'; statusIcon = ICONS.clock; statusRowColor = 'row-status-warning';
    } else {
        statusHtml = `<span class="badge badge-success">${badgeIcon('check')} Còn ${diffDays} ngày</span>`;
        statusIcon = ICONS.check; statusRowColor = 'row-status-success';
    }
}

// Tiến độ gần nhất = dòng tien_do cuối cùng (không cần gộp chuỗi rồi tách lại)
let latestUpdate = `<span class="empty">Chưa có cập nhật</span>`;
if (tienDo.length > 0) {
    const last = tienDo[tienDo.length - 1];
    latestUpdate = `<span class="up-content">${last.content}</span><span class="up-meta">${formatDateTime(last.time)} · ${last.name}</span>`;
}

// ===== ĐÍNH KÈM (của công việc + lần cập nhật tiến độ MỚI NHẤT) =====
// Bản copy đồng bộ với splitZaloAttachments/buildZaloAttachmentText trong src/lib/attachments.js.
// Sửa ở đây là PHẢI sửa cả bên đó (và ngược lại) — xem docs/n8n/nhac-viec-workflows.md.
// MỘT KHỐI duy nhất: ảnh NHÚNG vào lưới trong thẻ (HCTI render) → 10 ảnh vẫn là 1 tin nhắn.
// Video/file gửi link vì Zalo OA không có endpoint upload video.
const MAX_EMBED_IMAGES = 10;
const fmtSize = (b) => { const n = Number(b) || 0; return n < 1024 * 1024 ? Math.round(n / 1024) + 'KB' : (Math.round((n / 1024 / 1024) * 10) / 10) + 'MB'; };
const attsTask = Array.isArray(task.attachments) ? task.attachments : [];
const lastTien = tienDo.length ? tienDo[tienDo.length - 1] : null;
const attsTien = (lastTien && Array.isArray(lastTien.attachments)) ? lastTien.attachments : [];
const seenPath = new Set(); const atts = [];
for (const a of [...attsTask, ...attsTien]) {
    const k = a && (a.path || a.url);
    if (k && !seenPath.has(k)) { seenPath.add(k); atts.push(a); }
}
const zImages = [];   // ảnh nhúng vào thẻ; MỌI file đều có link riêng trong message_text
for (const a of atts) {
    if (a.kind === 'image' && zImages.length < MAX_EMBED_IMAGES) zImages.push(a);
}
const FILE_VIEW_BASE = 'https://thegioilocnuoc.site/webhook/f?p='; // webhook 'xem file' — link ngắn + Office viewer
const viewUrl = (a) => a.path ? FILE_VIEW_BASE + a.path : a.url;
// Nhãn "Bấm vào đây..." là dòng chữ ĐỨNG TRƯỚC link trần — Zalo không cho gắn chữ lên link.
// Liệt kê MỌI đính kèm kể cả ảnh đã nhúng: ảnh trong thẻ bị thu nhỏ và không bấm mở được.
const LINK_LABEL = { image: '🖼 Bấm vào đây để xem ảnh', video: '🎬 Bấm vào đây để xem video', file: '📄 Bấm vào đây xem file gửi kèm' };
const kindOfAtt = (a) => { if (a.kind) return a.kind; const m = String(a.mime || '').toLowerCase(); return m.indexOf('image/') === 0 ? 'image' : m.indexOf('video/') === 0 ? 'video' : 'file'; };
const attTotal = {}; for (const a of atts) { const k = kindOfAtt(a); attTotal[k] = (attTotal[k] || 0) + 1; }
const attSeen = {};
const attachText = atts.length
    ? '\n\n📎 Đính kèm:\n' + atts.map(a => {
        const k = kindOfAtt(a);
        attSeen[k] = (attSeen[k] || 0) + 1;
        const num = attTotal[k] > 1 ? ' (' + attSeen[k] + '/' + attTotal[k] + ')' : '';
        return (LINK_LABEL[k] || LINK_LABEL.file) + num + ' — ' + fmtSize(a.size) + ':\n' + viewUrl(a);
      }).join('\n')
    : '';
const nImg = atts.filter(a => a.kind === 'image').length;
const nVid = atts.filter(a => a.kind === 'video').length;
const nFile = atts.length - nImg - nVid;
const attachSummary = [nImg ? nImg + ' ảnh' : '', nVid ? nVid + ' video' : '', nFile ? nFile + ' tệp' : ''].filter(Boolean).join(', ');
const attachRow = atts.length ? `
            <div class="row row-attach">
                <div class="label"><span class="ic">${ICONS.content}</span>Đính kèm</div>
                <div class="value">${atts.length} file (${attachSummary}) — link từng file ở tin nhắn</div>
            </div>` : '';
// Ảnh càng ít càng phóng to; height auto để KHÔNG cắt (ảnh chụp màn hình phải đọc được chữ).
// Ảnh upload đã nén cạnh dài 1600px nên 1 ảnh hiện kích thước gốc là to nhất có thể, không upscale mờ.
const imgStyle = zImages.length === 1 ? 'width:auto;max-width:1700px'
    : zImages.length <= 4 ? 'width:880px' : 'width:580px';
const attachGrid = zImages.length ? `
            <div class="att-grid">${zImages.map(a => `<img class="att-img" style="${imgStyle}" src="${a.url}"/>`).join('')}</div>` : '';

const card = `
